import{_ as n,H as a,f as p,i as l}from"./chunks/framework.BHvCMIhP.js";const g=JSON.parse('{"title":"DevOps / SRE 总览:开发 vs 运维 vs SRE / 这个系列要解决什么","description":"","frontmatter":{},"headers":[],"relativePath":"devopsLearning/01-DevOps-SRE总览.md","filePath":"devopsLearning/01-DevOps-SRE总览.md","lastUpdated":1778496697000}'),e={name:"devopsLearning/01-DevOps-SRE总览.md"};function t(o,s,i,c,r,u){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="devops-sre-总览-开发-vs-运维-vs-sre-这个系列要解决什么" tabindex="-1">DevOps / SRE 总览:开发 vs 运维 vs SRE / 这个系列要解决什么 <a class="header-anchor" href="#devops-sre-总览-开发-vs-运维-vs-sre-这个系列要解决什么" aria-label="Permalink to &quot;DevOps / SRE 总览:开发 vs 运维 vs SRE / 这个系列要解决什么&quot;">​</a></h1><p>工程师对「DevOps / SRE」最大的误解是把它当成「<strong>升级版的运维</strong>」——以为加个监控、装个 Prometheus、上一套 K8s 就是 SRE 了。<strong>这是行业被工具厂商和招聘 JD 联手洗脑的结果</strong>。真相是:<strong>SRE 是一种用软件工程方法管理可靠性的工程范式,跟&quot;运维&quot;是两套技能树</strong>。运维问&quot;怎么把这台机器修好&quot;,SRE 问&quot;怎么让这台机器即使挂了业务也不掉&quot;——前者是修工(handyman),后者是工程师(engineer)。这种范式区别决定了:<strong>你不能靠&quot;招个高级运维&quot;做到 SRE,就像你不能靠&quot;招个高级前端&quot;做到产品经理</strong>——技能树压根没重叠。</p><blockquote><p>一句话先记住:<strong>DevOps 是一种文化主张(Dev 和 Ops 一体化),SRE 是这种主张的一个具体落地范式(用软件工程的方法学做可靠性)</strong>。Google 在 2003 年起把 SRE 做成内部职能,2016 年出了 SRE Book,从此整个行业有了一份&quot;可靠性工程&quot;的可参考蓝图——<strong>但这份蓝图建立在 Google 的规模、文化、薪资水平之上</strong>,中型团队照抄会出事。<strong>这个系列就是教你哪部分抄、哪部分改、哪部分别学</strong>。</p></blockquote><hr><h2 id="一、为什么应用工程师必须懂-sre" tabindex="-1">一、为什么应用工程师必须懂 SRE <a class="header-anchor" href="#一、为什么应用工程师必须懂-sre" aria-label="Permalink to &quot;一、为什么应用工程师必须懂 SRE&quot;">​</a></h2><h3 id="_1-1-三个让工程师破防的真实场景" tabindex="-1">1.1 三个让工程师破防的真实场景 <a class="header-anchor" href="#_1-1-三个让工程师破防的真实场景" aria-label="Permalink to &quot;1.1 三个让工程师破防的真实场景&quot;">​</a></h3><p><strong>场景 1:你上线了一个&quot;小改动&quot;,凌晨被叫醒,发现&quot;小改动&quot;动了某个全局配置</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>周五下午 17:30,你把一个 PR 合进 main 分支:</span></span>
<span class="line"><span>   把日志级别从 INFO 改成 DEBUG,方便下周排查一个偶发问题</span></span>
<span class="line"><span>   CI 绿,review 也过了,没人多想</span></span>
<span class="line"><span></span></span>
<span class="line"><span>周六凌晨 02:30,告警炸了:</span></span>
<span class="line"><span>   - 磁盘 99% 满</span></span>
<span class="line"><span>   - 应用因日志写入失败开始 5xx</span></span>
<span class="line"><span>   - DEBUG 日志把交易流水的明文打了出来(合规告警)</span></span></code></pre></div><p><strong>这个场景的核心不是&quot;代码写错了&quot;</strong>——代码完全合规,review 也过了。<strong>核心是没有人对&quot;上线之后&quot;负责</strong>:没有 SLO(磁盘满到 80% 该不该告警没人定)、没有发布门禁(日志级别变更没标识为&quot;高风险变更&quot;)、没有 On-call 体系(凌晨告警没人接)、没有可观测性(磁盘从 50% 飙到 99% 的过程没有人看)。<strong>所有&quot;开发完了就完了&quot;的团队,都在等这种事故发生</strong>。</p><p><strong>场景 2:你给客户承诺 &quot;99.9% 可用&quot;,签合同时没人算这意味着什么</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>销售给客户写了&quot;系统可用性 SLA: 99.9%&quot;</span></span>
<span class="line"><span>工程师签字:&quot;应该没问题吧,我们 prod 看起来很稳&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>三个月后客户来对账:</span></span>
<span class="line"><span>   &quot;你们这个季度有 3 次故障,每次 1 小时,合计 3 小时&quot;</span></span>
<span class="line"><span>   &quot;按 SLA,这季度允许 3*30*24*60*0.001 = 130 分钟下线&quot;</span></span>
<span class="line"><span>   &quot;你们超了 50 分钟,按合同要赔 ¥20 万&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>工程师才想起来:</span></span>
<span class="line"><span>   - SLA 是合同概念,SLO 是工程目标,SLI 是测量指标</span></span>
<span class="line"><span>   - 这三个字母组合从来没在工程团队定义过</span></span>
<span class="line"><span>   - 客户的&quot;故障&quot;定义和你的不一样(客户算&quot;打不开&quot;,你算&quot;5xx&quot;)</span></span>
<span class="line"><span>   - 你连&quot;过去 90 天累计可用时间&quot;都没度量</span></span></code></pre></div><p><strong>这个场景的根因是 SLI / SLO / SLA 三件套从未在工程团队建立</strong>。SRE 工程的一半工作是把&quot;业务承诺&quot;和&quot;工程现实&quot;通过这三个字母对齐——<strong>没有这套语言,商务上的承诺就是空头支票</strong>。</p><p><strong>场景 3:你的告警群每天 200 条消息,没人看了,真出事时埋在噪声里</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>团队群 #alerts 看起来很专业:</span></span>
<span class="line"><span>   - 每天 200+ 条告警刷屏</span></span>
<span class="line"><span>   - &quot;CPU &gt; 80%&quot;  —— 一天来 30 次,大家都不看了</span></span>
<span class="line"><span>   - &quot;P99 &gt; 500ms&quot; —— 一天 50 次,新人以为是日志</span></span>
<span class="line"><span>   - &quot;节点 NotReady 1min 后恢复&quot; —— 一天 10 次</span></span>
<span class="line"><span></span></span>
<span class="line"><span>某天凌晨,真的核心 DB 连接池打满:</span></span>
<span class="line"><span>   - 告警在 02:11 准时发出</span></span>
<span class="line"><span>   - 03:45 客服群炸了,工程师才意识到告警群里有一条</span></span>
<span class="line"><span>   - 中间 90 分钟,P0 在 200 条噪声里被忽略</span></span></code></pre></div><p><strong>这个场景的核心是&quot;告警工程&quot;没做</strong>:静态阈值告警必然爆炸、多燃烧率没用、告警没有分级、误报没有反馈机制。<strong>告警系统不是&quot;装上 Prometheus 就完事&quot;,是一套需要持续运营的工程产品</strong>。</p><h3 id="_1-2-这三个场景的共同点" tabindex="-1">1.2 这三个场景的共同点 <a class="header-anchor" href="#_1-2-这三个场景的共同点" aria-label="Permalink to &quot;1.2 这三个场景的共同点&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>不是&quot;代码不够好&quot;        —— 代码 review 都过了</span></span>
<span class="line"><span>不是&quot;工程师不努力&quot;      —— 都是合理工作</span></span>
<span class="line"><span>不是&quot;工具不够多&quot;        —— Prometheus / 告警群都有</span></span>
<span class="line"><span></span></span>
<span class="line"><span>是&quot;代码合上去之后的事没人系统化做&quot;</span></span>
<span class="line"><span>   —— 没人定 SLO / 没人配告警分级 / 没人写 Runbook</span></span>
<span class="line"><span>   —— 没人排 On-call / 没人做复盘 / 没人跟踪根因修复</span></span>
<span class="line"><span>   —— 没人把&quot;业务承诺&quot;翻译成&quot;工程指标&quot;</span></span>
<span class="line"><span>   —— 没人在告警风暴里识别真信号</span></span></code></pre></div><p><strong>这就是 SRE 工程要解决的问题</strong>:<strong>让&quot;代码上线&quot;和&quot;系统可靠&quot;成为两件被独立、可量化、可改进的工程</strong>。你写代码再好,这一半工作不做,生产系统就是一颗等待引爆的雷。</p><hr><h2 id="二、devops-和-sre-是什么-以及它们的关系" tabindex="-1">二、DevOps 和 SRE 是什么,以及它们的关系 <a class="header-anchor" href="#二、devops-和-sre-是什么-以及它们的关系" aria-label="Permalink to &quot;二、DevOps 和 SRE 是什么,以及它们的关系&quot;">​</a></h2><p>讲这两个词最大的混乱来自:<strong>业界对它们的定义从来没统一过</strong>。我下面给的是&quot;对中型团队最有用的&quot;版本,不是&quot;最学术正确&quot;的版本——后者你去问 ChatGPT 能问出 10 种答案。</p><h3 id="_2-1-devops-一种文化主张" tabindex="-1">2.1 DevOps:一种文化主张 <a class="header-anchor" href="#_2-1-devops-一种文化主张" aria-label="Permalink to &quot;2.1 DevOps:一种文化主张&quot;">​</a></h3><p><strong>DevOps 的本意</strong>:打破&quot;开发(Dev)&quot;和&quot;运维(Ops)&quot;之间的墙——让写代码的人对&quot;代码上线后跑得好不好&quot;负责,让做运维的人参与到&quot;代码怎么设计才好维护&quot;的早期讨论。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>传统组织(2010 年前主流):</span></span>
<span class="line"><span>   ┌───────────┐    ─────扔过墙─────▶    ┌───────────┐</span></span>
<span class="line"><span>   │   开发    │    &quot;代码我写完了&quot;        │   运维    │</span></span>
<span class="line"><span>   │           │    ◀──────抗议──────    │           │</span></span>
<span class="line"><span>   │ &quot;为什么 │                            │ &quot;你这代码 │</span></span>
<span class="line"><span>   │  上线慢?&quot;│                            │  没法部署&quot;│</span></span>
<span class="line"><span>   └───────────┘                          └───────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   开发追求&quot;快&quot;(新功能),运维追求&quot;稳&quot;(不变更)</span></span>
<span class="line"><span>   两者的 KPI 直接冲突</span></span></code></pre></div><p>DevOps 主张<strong>这堵墙不该存在</strong>——开发也要懂部署,运维也要参与设计,<strong>两边共享 KPI</strong>(发布速度 + 系统稳定)。</p><p>但 DevOps <strong>只是文化主张,不是具体方法论</strong>——它没告诉你:</p><ul><li>怎么具体度量&quot;稳定&quot;?</li><li>谁来负责&quot;出事时谁先看告警&quot;?</li><li>发布失败该怎么定义&quot;失败&quot;?</li><li>运维工作和开发工作的边界在哪?</li></ul><p>这些问题留给了&quot;具体落地方&quot;——SRE 是其中一个落地方。</p><h3 id="_2-2-sre-google-给出的具体范式" tabindex="-1">2.2 SRE:Google 给出的具体范式 <a class="header-anchor" href="#_2-2-sre-google-给出的具体范式" aria-label="Permalink to &quot;2.2 SRE:Google 给出的具体范式&quot;">​</a></h3><p><strong>SRE(Site Reliability Engineering)是 Google 在 2003 年起内部职能,2016 年出了 SRE Book,把这套范式公开化</strong>。SRE 的核心主张:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SRE = 用软件工程的方法做可靠性</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  把&quot;运维&quot;重新拆解:</span></span>
<span class="line"><span>   - 哪些是机械重复的(Toil)     → 自动化掉</span></span>
<span class="line"><span>   - 哪些是可工程化的(SLO/告警)  → 做成可量化的产品</span></span>
<span class="line"><span>   - 哪些是需要判断的(事故响应) → 用流程和角色来规范</span></span>
<span class="line"><span>   - 哪些是必须人在场的(决策)   → 留给人,但用工具放大</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  然后,招&quot;会写代码&quot;的人来做这套事</span></span>
<span class="line"><span>   ——这就是 SRE,不是高级运维</span></span></code></pre></div><p>SRE Book 里给了 Google 内部的 4 条铁律(详见下一篇):</p><ol><li><strong>错误预算(Error Budget)</strong>——把&quot;100% 可用&quot;翻译成&quot;允许 X 分钟不可用&quot;,这 X 分钟是创新的预算</li><li><strong>Toil 上限</strong>——SRE 不得超过 50% 时间在机械重复工作上,否则任务退回开发</li><li><strong>黄金信号(Golden Signals)</strong>——一个服务该看的 4 个核心指标:Latency / Traffic / Errors / Saturation</li><li><strong>Blameless Postmortem</strong>——事故复盘只追流程不追个人</li></ol><p>这 4 条加在一起,<strong>构成了&quot;可靠性工程&quot;的最小可行范式</strong>。后续的所有工具(Prometheus / Grafana / ArgoCD / PagerDuty)都是这套范式的某个环节的工具化。</p><h3 id="_2-3-devops-和-sre-的关系" tabindex="-1">2.3 DevOps 和 SRE 的关系 <a class="header-anchor" href="#_2-3-devops-和-sre-的关系" aria-label="Permalink to &quot;2.3 DevOps 和 SRE 的关系&quot;">​</a></h3><p>最简洁的描述(也是 Google 自己的说法):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                                                          │</span></span>
<span class="line"><span>│  DevOps:一种文化主张(&quot;Dev 和 Ops 应该一体化&quot;)           │</span></span>
<span class="line"><span>│     │                                                    │</span></span>
<span class="line"><span>│     ├── 实践 A:全栈工程师承担运维(小团队常见)            │</span></span>
<span class="line"><span>│     │                                                    │</span></span>
<span class="line"><span>│     ├── 实践 B:平台工程(Platform Engineering)           │</span></span>
<span class="line"><span>│     │   平台团队建工具,业务团队自助使用                   │</span></span>
<span class="line"><span>│     │                                                    │</span></span>
<span class="line"><span>│     └── 实践 C:SRE(Google 范式)                         │</span></span>
<span class="line"><span>│         专职 SRE 团队,用工程方法做可靠性                  │</span></span>
<span class="line"><span>│                                                          │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>class SRE implements DevOps</span></span></code></pre></div><p><strong>SRE 是 DevOps 的一个具体子类,不是 DevOps 的替代品也不是升级版</strong>。一个团队可以做 DevOps 但没有 SRE 编制(用全栈做),也可以有 SRE 编制但 DevOps 文化烂(SRE 和开发互相甩锅)。</p><h3 id="_2-4-sre-高级运维" tabindex="-1">2.4 SRE ≠ 高级运维 <a class="header-anchor" href="#_2-4-sre-高级运维" aria-label="Permalink to &quot;2.4 SRE ≠ 高级运维&quot;">​</a></h3><p>国内招聘市场最大的坑:<strong>「SRE 工程师」JD 写成了「高级运维」JD</strong>——</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>典型的&quot;假 SRE&quot;JD:</span></span>
<span class="line"><span>   - 负责 Linux 系统维护和故障排查</span></span>
<span class="line"><span>   - 熟悉 K8s / Docker / Nginx 部署</span></span>
<span class="line"><span>   - 7x24 On-call 应急响应</span></span>
<span class="line"><span>   - 能写 Shell / Python 脚本</span></span>
<span class="line"><span>   - 加分:有 Ansible / Terraform 经验</span></span>
<span class="line"><span></span></span>
<span class="line"><span>真正的 SRE JD 应该长这样:</span></span>
<span class="line"><span>   - 设计和实施 SLI / SLO,推动可靠性目标量化</span></span>
<span class="line"><span>   - 用软件工程方法降低 Toil(自动化、平台化)</span></span>
<span class="line"><span>   - 主导事故响应流程,组织 Blameless Postmortem</span></span>
<span class="line"><span>   - 设计告警策略(多燃烧率、SLO-based)</span></span>
<span class="line"><span>   - 用代码而不是工单解决重复问题</span></span>
<span class="line"><span>   - 加分:会 Go / Rust 写工具,会 PromQL,理解分布式系统理论</span></span></code></pre></div><p><strong>两份 JD 的差别本质上是</strong>:运维是&quot;修工&quot;,SRE 是&quot;工程师&quot;。运维处理&quot;现在出的问题&quot;,SRE 设计&quot;以后不会出这个问题&quot;的系统。前者用工单,后者用 PR。</p><p><strong>国内为什么会有这个错位</strong>:</p><ol><li>传统运维团队转型 SRE,但只换了名字没换技能</li><li>招聘市场上&quot;会写代码的运维&quot;贵,公司想找便宜的</li><li>业务团队不想自己 On-call,把 SRE 当替罪羊</li></ol><p>这三条加在一起,造成了&quot;SRE 工程师&quot;在国内 80% 的实际工作就是高级运维。<strong>这个系列不接受这种定义</strong>——本系列讲的 SRE 是 Google 那种 SRE,即使你的 title 是&quot;高级运维&quot;,看完这套你做的就是 SRE 的事。</p><hr><h2 id="三、google-sre-在中国小团队为什么跑不通" tabindex="-1">三、Google SRE 在中国小团队为什么跑不通 <a class="header-anchor" href="#三、google-sre-在中国小团队为什么跑不通" aria-label="Permalink to &quot;三、Google SRE 在中国小团队为什么跑不通&quot;">​</a></h2><p>SRE Book 是好书,<strong>但中型团队照抄会出事</strong>——因为这本书建立在 Google 的若干前提之上,这些前提在中型团队都不成立。</p><h3 id="_3-1-google-的前提条件" tabindex="-1">3.1 Google 的前提条件 <a class="header-anchor" href="#_3-1-google-的前提条件" aria-label="Permalink to &quot;3.1 Google 的前提条件&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SRE Book 隐含的前提:</span></span>
<span class="line"><span>   1. 你有专职 SRE 编制(不是兼职,不是甩锅给运维)</span></span>
<span class="line"><span>   2. SRE 和开发是平等谈判方(不是 SRE 给开发打杂)</span></span>
<span class="line"><span>   3. 业务方接受&quot;错误预算用完就停发版&quot;(不是销售压一切)</span></span>
<span class="line"><span>   4. 工程师工资足够高,不能 burnout(Google 工程师起薪 30 万美元)</span></span>
<span class="line"><span>   5. 系统规模够大,自动化 ROI 足够(每个工具花一个月开发,值)</span></span>
<span class="line"><span>   6. 公司业务多样化,某条线挂一会儿不影响整体(不是 to B 单产品)</span></span></code></pre></div><p><strong>这 6 条前提任何一条不满足,SRE Book 的某些建议就跑不通</strong>——这是这一节的核心论点。</p><h3 id="_3-2-中型团队的真实约束" tabindex="-1">3.2 中型团队的真实约束 <a class="header-anchor" href="#_3-2-中型团队的真实约束" aria-label="Permalink to &quot;3.2 中型团队的真实约束&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  中型团队的真实约束(10 人 / 100 微服务 / 5000 QPS)      │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  约束 1:没有专职 SRE                                    │</span></span>
<span class="line"><span>│    最多 1-2 个&quot;DevOps 工程师&quot;,还兼着 CI/CD              │</span></span>
<span class="line"><span>│    → 50% 工程时间没法切割,人都不够分                    │</span></span>
<span class="line"><span>│                                                         │</span></span>
<span class="line"><span>│  约束 2:开发兼 On-call                                  │</span></span>
<span class="line"><span>│    SRE 和开发不是平等谈判方,SRE 是被领导的角色          │</span></span>
<span class="line"><span>│    → 错误预算的&quot;政治&quot;没有谈判台                          │</span></span>
<span class="line"><span>│                                                         │</span></span>
<span class="line"><span>│  约束 3:销售导向,业务方刹不住车                        │</span></span>
<span class="line"><span>│    &quot;下周必须上&quot;是常态,&quot;停发版&quot;是奢侈品                  │</span></span>
<span class="line"><span>│    → 错误预算政策只能软执行                              │</span></span>
<span class="line"><span>│                                                         │</span></span>
<span class="line"><span>│  约束 4:工程师产能稀缺                                  │</span></span>
<span class="line"><span>│    自动化一个 Toil 要 1 周,Toil 本身一周才出 5 次       │</span></span>
<span class="line"><span>│    → 不是所有 Toil 都值得自动化                          │</span></span>
<span class="line"><span>│                                                         │</span></span>
<span class="line"><span>│  约束 5:业务集中,挂一会儿就是事故                      │</span></span>
<span class="line"><span>│    一个核心 API 挂 10 分钟,客户就在打投诉电话           │</span></span>
<span class="line"><span>│    → 错误预算的&quot;积累&quot;机制不适用                          │</span></span>
<span class="line"><span>│                                                         │</span></span>
<span class="line"><span>│  约束 6:工资压力下,On-call 加班费不一定能配齐          │</span></span>
<span class="line"><span>│    深夜被叫醒一次 ¥100,但实际生理代价 ¥500              │</span></span>
<span class="line"><span>│    → On-call 制度的&quot;激励&quot;很难拉齐到 Google 水平          │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="_3-3-直接抄-sre-book-的典型翻车" tabindex="-1">3.3 直接抄 SRE Book 的典型翻车 <a class="header-anchor" href="#_3-3-直接抄-sre-book-的典型翻车" aria-label="Permalink to &quot;3.3 直接抄 SRE Book 的典型翻车&quot;">​</a></h3><p>我见过的真实事故:</p><p><strong>翻车 1:招了个&quot;SRE&quot;,其实是高级运维</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>团队招了一个&quot;SRE 工程师&quot;</span></span>
<span class="line"><span>JD 写得很 SRE,实际工作:</span></span>
<span class="line"><span>  - 每周接 50 个工单(扩容 / 续费 / 报错排查)</span></span>
<span class="line"><span>  - 写了 3 个月没写超过 100 行代码</span></span>
<span class="line"><span>  - 业务团队继续把他当&quot;运维&quot;,有需求就提单</span></span>
<span class="line"><span>  - 半年后辞职:&quot;这不是我想做的工作&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>教训:招 SRE 之前,业务团队的 mindset 没改,</span></span>
<span class="line"><span>      SRE 进来只会被消耗成高级运维</span></span></code></pre></div><p><strong>翻车 2:照搬&quot;错误预算用完停发版&quot;</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>团队读完 SRE Book,定 SLO 99.9%</span></span>
<span class="line"><span>某月错误预算超支,SRE 宣布&quot;停发版一周&quot;</span></span>
<span class="line"><span>业务方:&quot;客户等着这个功能,你们停发版客户跑了&quot;</span></span>
<span class="line"><span>拉了一个会,业务方赢了,继续发</span></span>
<span class="line"><span>SRE 此后不再敢提&quot;停发版&quot;,错误预算政策名存实亡</span></span>
<span class="line"><span></span></span>
<span class="line"><span>教训:错误预算是一种&quot;权力工具&quot;,</span></span>
<span class="line"><span>      你没有让业务方接受的政治资本,这工具就是摆设</span></span></code></pre></div><p><strong>翻车 3:盲目追求 50% 工程时间</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>团队 5 个开发 + 1 个 SRE</span></span>
<span class="line"><span>SRE Lead 看完 SRE Book,定&quot;SRE 不超过 50% Toil&quot;</span></span>
<span class="line"><span>实际情况:每周告警 80 条,Toil 全部由 SRE 一人承担</span></span>
<span class="line"><span>SRE 加班到 60% 都打不住,新工程一行没做</span></span>
<span class="line"><span>6 个月后 SRE 辞职,告警群没人值</span></span>
<span class="line"><span></span></span>
<span class="line"><span>教训:50% 时间是组织设计,不是个人努力</span></span>
<span class="line"><span>      你只有 1 个 SRE,这条线本来就是单点失败</span></span></code></pre></div><h3 id="_3-4-那这本书还要不要读" tabindex="-1">3.4 那这本书还要不要读 <a class="header-anchor" href="#_3-4-那这本书还要不要读" aria-label="Permalink to &quot;3.4 那这本书还要不要读&quot;">​</a></h3><p><strong>要读,但要&quot;批判性地读&quot;</strong>——把 SRE Book 当成&quot;参考架构&quot;,不是&quot;实施指南&quot;:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>读 SRE Book 的正确姿势:</span></span>
<span class="line"><span>   1. 学概念:错误预算 / Toil / 黄金信号 / Postmortem 都是真理</span></span>
<span class="line"><span>   2. 学方法学:SLO 怎么定、告警怎么配、复盘怎么开</span></span>
<span class="line"><span>   3. 学组织设计:理解 Google 为什么这么做,而不是照抄</span></span>
<span class="line"><span>   4. 学反面教材:Google 自己也讲了哪些&quot;我们试过不行的&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不要直接照抄的:</span></span>
<span class="line"><span>   1. 50% 时间(改成&quot;每人每周 1 天非告警时间&quot;)</span></span>
<span class="line"><span>   2. SRE 和开发的&quot;权力平衡&quot;(在中国得靠 CTO 兜底)</span></span>
<span class="line"><span>   3. 错误预算的&quot;停发版&quot;硬约束(改成&quot;软警告 + 升级&quot;)</span></span>
<span class="line"><span>   4. 大规模自动化(只自动化 ROI 正的)</span></span></code></pre></div><p><strong>这个系列就是 SRE Book 的&quot;中型团队改造版&quot;</strong>——把那些值钱的概念落地到 10 人团队 / 5000 QPS 的真实约束下,把那些跑不通的直接砍掉或重写。</p><hr><h2 id="四、本系列的定位和读者画像" tabindex="-1">四、本系列的定位和读者画像 <a class="header-anchor" href="#四、本系列的定位和读者画像" aria-label="Permalink to &quot;四、本系列的定位和读者画像&quot;">​</a></h2><h3 id="_4-1-读者画像" tabindex="-1">4.1 读者画像 <a class="header-anchor" href="#_4-1-读者画像" aria-label="Permalink to &quot;4.1 读者画像&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你应该长这样:</span></span>
<span class="line"><span>   - 写 Java / Go / Node,代码量 3+ 年</span></span>
<span class="line"><span>   - 知道 K8s / Docker 基础,做过几次部署</span></span>
<span class="line"><span>   - 团队 5-30 人,业务流量 100-10000 QPS</span></span>
<span class="line"><span>   - 见过几次生产事故,但还没系统化处理过</span></span>
<span class="line"><span>   - 已经在用 Prometheus / Grafana,但不知道有没有用对</span></span>
<span class="line"><span>   - 想把&quot;代码合到 main&quot;和&quot;系统可靠&quot;两件事都做好</span></span></code></pre></div><p><strong>这个系列不服务</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✗ 完全没生产经验的学生</span></span>
<span class="line"><span>  → 先去 backendLearning 把基础打牢,33/34 篇足够入门</span></span>
<span class="line"><span>✗ 大厂的全职 SRE</span></span>
<span class="line"><span>  → 你们的规模问题(全球流量 / 万级服务)本系列不讲</span></span>
<span class="line"><span>✗ 纯运维 / DBA / 网络工程师</span></span>
<span class="line"><span>  → 这里的视角是&quot;应用工程师视角&quot;,DBA 视角的可靠性请另找</span></span>
<span class="line"><span>✗ AI / Agent 系统的 SRE</span></span>
<span class="line"><span>  → AI 系统的可观测性 / 评估 / 安全有专门体系,在 aiLearning</span></span></code></pre></div><h3 id="_4-2-这个系列的写作主线" tabindex="-1">4.2 这个系列的写作主线 <a class="header-anchor" href="#_4-2-这个系列的写作主线" aria-label="Permalink to &quot;4.2 这个系列的写作主线&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每一篇都回答同一个问题:</span></span>
<span class="line"><span>   &quot;这件事不做会怎样,做了能多扛多少事故&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不讲:</span></span>
<span class="line"><span>   ✗ &quot;业界最佳实践&quot;这种空话</span></span>
<span class="line"><span>   ✗ &quot;Google 是怎么做的&quot;原话搬运</span></span>
<span class="line"><span>   ✗ Datadog / New Relic 的市场白皮书</span></span>
<span class="line"><span></span></span>
<span class="line"><span>讲:</span></span>
<span class="line"><span>   ✓ &quot;我们团队 10 人 / 100 微服务 / 5000 QPS,这件事该不该做&quot;</span></span>
<span class="line"><span>   ✓ &quot;做到什么程度,什么时候停&quot;</span></span>
<span class="line"><span>   ✓ &quot;做错了会出什么事,怎么救&quot;</span></span></code></pre></div><h3 id="_4-3-一条贯穿全系列的暗线-三个数字" tabindex="-1">4.3 一条贯穿全系列的暗线:三个数字 <a class="header-anchor" href="#_4-3-一条贯穿全系列的暗线-三个数字" aria-label="Permalink to &quot;4.3 一条贯穿全系列的暗线:三个数字&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MTTR(Mean Time To Recovery,故障恢复时间)</span></span>
<span class="line"><span>   → 故障发生到恢复的平均时间</span></span>
<span class="line"><span>   → 第二层(可观测性)让你能更快定位故障</span></span>
<span class="line"><span>   → 第六层(On-call / 事故响应)让你能更快协调修复</span></span>
<span class="line"><span></span></span>
<span class="line"><span>MTBF(Mean Time Between Failures,故障间隔时间)</span></span>
<span class="line"><span>   → 两次故障之间的平均时间</span></span>
<span class="line"><span>   → 第三层(SLO / 告警)让你提前发现 MTBF 在变短</span></span>
<span class="line"><span>   → 第四层(渐进发布)让发布不直接拉短 MTBF</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Change Failure Rate(发布失败率)</span></span>
<span class="line"><span>   → 多少比例的发布导致事故</span></span>
<span class="line"><span>   → 第四层(CI/CD / GitOps)让发布失败概率降低</span></span>
<span class="line"><span>   → 第五层(IaC)让&quot;配置发布失败&quot;也可控</span></span>
<span class="line"><span></span></span>
<span class="line"><span>复盘(Postmortem)</span></span>
<span class="line"><span>   → 把这三个数字闭环——出事后哪个变差了,怎么改进</span></span>
<span class="line"><span>   → 第六层(33 篇)讲清楚怎么开复盘不变扯皮</span></span></code></pre></div><p><strong>每读完一层,回头看一眼</strong>:<strong>我把这三个数字往哪个方向推了</strong>?如果你不能说出一篇文章怎么影响这三个数字之一,那篇文章对你团队就没价值。</p><hr><h2 id="五、34-篇地图-六层结构" tabindex="-1">五、34 篇地图:六层结构 <a class="header-anchor" href="#五、34-篇地图-六层结构" aria-label="Permalink to &quot;五、34 篇地图:六层结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 第六层:生产实战(28-34)                                     │</span></span>
<span class="line"><span>│   On-call / Runbook / 容量 / 混沌 / 事故 / 复盘 / FinOps    │</span></span>
<span class="line"><span>│   面试和真实工作的硬通货,7 篇                                │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 第五层:IaC 与配置管理(24-27)                                │</span></span>
<span class="line"><span>│   IaC 心智 / Terraform / Pulumi / 配置管理                  │</span></span>
<span class="line"><span>│   最容易半途而废的一层,4 篇                                  │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 第四层:CI/CD 与发布工程(18-23)                              │</span></span>
<span class="line"><span>│   CI/CD 心智 / 制品仓库 / GitOps / 渐进发布 / FF / DB 变更   │</span></span>
<span class="line"><span>│   最贴日常,80% 团队不及格,6 篇                              │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 第三层:SLO 与告警工程(13-17)                                │</span></span>
<span class="line"><span>│   SLI/SLO/SLA / RED&amp;USE / 告警分级 / 仪表盘 / 错误预算政治  │</span></span>
<span class="line"><span>│   最反直觉,讲完你才知道告警为什么一直爆炸,5 篇              │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 第二层:可观测性三件套(05-12)                                │</span></span>
<span class="line"><span>│   Metrics / Prometheus / PromQL / VM-Thanos / Logs /        │</span></span>
<span class="line"><span>│   日志采集 / OTel / Profiling                                │</span></span>
<span class="line"><span>│   最值钱的一层,90% 事故先在这里发现,8 篇                    │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 第一层:DevOps / SRE 心智(01-04)                            │</span></span>
<span class="line"><span>│   总览(本篇) / Google SRE 精华 / 可观测性是什么 / 四真相    │</span></span>
<span class="line"><span>│   地基,看完知道&quot;SRE 不是高级运维&quot;,4 篇                     │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="_5-1-每层学完能解决什么" tabindex="-1">5.1 每层学完能解决什么 <a class="header-anchor" href="#_5-1-每层学完能解决什么" aria-label="Permalink to &quot;5.1 每层学完能解决什么&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一层(01-04):</span></span>
<span class="line"><span>   学完能在白板上回答:</span></span>
<span class="line"><span>   - &quot;SRE 和 DevOps 是什么关系&quot;</span></span>
<span class="line"><span>   - &quot;为什么 99.9% 一个月只有 43 分钟错误预算&quot;</span></span>
<span class="line"><span>   - &quot;Monitoring 和 Observability 的区别&quot;</span></span>
<span class="line"><span>   - &quot;失败是常态,你的代码假设过这点吗&quot;</span></span>
<span class="line"><span>   解决:团队 mindset 对齐,不再把 SRE 当运维</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二层(05-12):</span></span>
<span class="line"><span>   学完能在 PR 评审里指出:</span></span>
<span class="line"><span>   - &quot;这个 metric 用 user_id 当 label 会让 Prometheus 挂掉&quot;</span></span>
<span class="line"><span>   - &quot;这条 PromQL 用 increase 算 QPS 是错的&quot;</span></span>
<span class="line"><span>   - &quot;OpenTelemetry 的 traceparent 没透传&quot;</span></span>
<span class="line"><span>   - &quot;持续 profiling 没接上 GO_PPROF 端口&quot;</span></span>
<span class="line"><span>   解决:观测到故障的能力,从&quot;事后捞日志&quot;到&quot;实时定位&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三层(13-17):</span></span>
<span class="line"><span>   学完能给团队定:</span></span>
<span class="line"><span>   - 一份 SLO 文档(SLI 选择 + 错误预算政策)</span></span>
<span class="line"><span>   - 一份多窗口多燃烧率的告警规则</span></span>
<span class="line"><span>   - 一份&quot;哪些 dashboard 必须保留,哪些是垃圾&quot;的清单</span></span>
<span class="line"><span>   解决:告警噪音 90% 削减,真信号不被淹</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四层(18-23):</span></span>
<span class="line"><span>   学完能给团队做:</span></span>
<span class="line"><span>   - 一份 GitOps 工作流(ArgoCD + 多环境 promote)</span></span>
<span class="line"><span>   - 一份金丝雀发布门禁(自动 rollback 条件)</span></span>
<span class="line"><span>   - 一份 Feature Flag 设计模板</span></span>
<span class="line"><span>   解决:Change Failure Rate 从 30% 降到 5% 以下</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第五层(24-27):</span></span>
<span class="line"><span>   学完能给团队建:</span></span>
<span class="line"><span>   - 一份 IaC 仓库结构(三层分层 + Module 设计)</span></span>
<span class="line"><span>   - 一份 State 管理规范(远程后端 + 锁 + 加密)</span></span>
<span class="line"><span>   - 一份 Drift 治理流程(定期 detect + 紧急修复)</span></span>
<span class="line"><span>   解决:基础设施&quot;漂移&quot;从&quot;半年差 40%&quot;到&quot;每周差 1%&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第六层(28-34):</span></span>
<span class="line"><span>   学完能给团队建:</span></span>
<span class="line"><span>   - 一份 On-call 制度(轮值 + Pager + 升级路径)</span></span>
<span class="line"><span>   - 一份 Runbook 库(任何值班人能跑)</span></span>
<span class="line"><span>   - 一份事故响应手册(IC/Ops/Comms 角色 + 战时频道模板)</span></span>
<span class="line"><span>   - 一份成本可观测性的 dashboard</span></span>
<span class="line"><span>   解决:MTTR 从&quot;2 小时&quot;到&quot;30 分钟&quot;,团队从&quot;靠英雄&quot;到&quot;靠流程&quot;</span></span></code></pre></div><h3 id="_5-2-不同角色的最小阅读路径" tabindex="-1">5.2 不同角色的最小阅读路径 <a class="header-anchor" href="#_5-2-不同角色的最小阅读路径" aria-label="Permalink to &quot;5.2 不同角色的最小阅读路径&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  角色           │ 必读           │ 选读                     │</span></span>
<span class="line"><span>├─────────────────┼────────────────┼──────────────────────────┤</span></span>
<span class="line"><span>│ 应用开发        │ 01-04, 13-17,  │ 24-27(改基础设施)        │</span></span>
<span class="line"><span>│                 │ 18-23, 28-29   │                          │</span></span>
<span class="line"><span>├─────────────────┼────────────────┼──────────────────────────┤</span></span>
<span class="line"><span>│ 高级开发 / Lead │ 01-17, 28-34   │ 18-27(具体落地)          │</span></span>
<span class="line"><span>├─────────────────┼────────────────┼──────────────────────────┤</span></span>
<span class="line"><span>│ SRE / DevOps    │ 全部           │                          │</span></span>
<span class="line"><span>├─────────────────┼────────────────┼──────────────────────────┤</span></span>
<span class="line"><span>│ 架构师 / 技术   │ 01-04, 13-17,  │ 05-12(具体可观测性栈)    │</span></span>
<span class="line"><span>│  CTO            │ 28-34          │                          │</span></span>
<span class="line"><span>├─────────────────┼────────────────┼──────────────────────────┤</span></span>
<span class="line"><span>│ 平台工程        │ 01-04, 18-27,  │ 13-17(SLO 工程)          │</span></span>
<span class="line"><span>│                 │ 34             │                          │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>应用开发的核心阅读 = 第一层 + 第三层 + 第四层 + 第六层前两篇</strong>——加起来 14 篇,涵盖&quot;代码上线之后该懂的最少东西&quot;。<strong>SRE / DevOps 必须全读</strong>,这是岗位职责。<strong>架构师不必深入到 PromQL 细节,但 SLO / Postmortem / 容量规划必须懂</strong>。</p><hr><h2 id="六、与其他系列的边界" tabindex="-1">六、与其他系列的边界 <a class="header-anchor" href="#六、与其他系列的边界" aria-label="Permalink to &quot;六、与其他系列的边界&quot;">​</a></h2><p>我有 7 个技术系列,这一个是&quot;上线之后&quot;的视角。<strong>怎么跟其他 6 个区分,看下表</strong>:</p><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>Docker / K8s 部署</td><td>backendLearning/24-30 ✅</td><td>不重复,只在 IaC / GitOps 里讲 K8s 上的发布</td></tr><tr><td>微服务 / 服务网格</td><td>backendLearning/32 / 60 ✅</td><td>不重复,只讲服务网格出的指标怎么读</td></tr><tr><td>监控基础 / 日志基础</td><td>backendLearning/33-34 ✅</td><td>升级,讲选型 / PromQL / OTel / 长存储</td></tr><tr><td>CICD 基础</td><td>backendLearning/40 ✅</td><td>升级,讲 GitOps / 渐进发布 / 制品安全</td></tr><tr><td>SRE 入门</td><td>backendLearning/59 ✅</td><td>升级,讲 SLO 算术 / On-call / 复盘工程</td></tr><tr><td>IaC 基础</td><td>backendLearning/58 ✅</td><td>升级,讲 state / drift / module 设计</td></tr><tr><td>限流熔断 / 任务调度</td><td>backendLearning/43-44 ✅</td><td>不重复,只在容量规划一篇引用</td></tr><tr><td>压测</td><td>backendLearning/36 ✅</td><td>不重复,本系列把压测结果接到容量模型</td></tr><tr><td>反向代理 / WAF / 排障</td><td>networkLearning ✅</td><td>不重复,只在链路追踪一篇引用</td></tr><tr><td>性能工具 / eBPF</td><td>osLearning/26-27 ✅</td><td>不重复,只讲&quot;持续性能剖析&quot;工程化</td></tr><tr><td>抗压 / 容灾 / 多机房 / 灰度</td><td>systemDesign ✅</td><td>不重复,只讲容量规划落地与混沌演练</td></tr><tr><td>安全监控 / 应急响应(安全侧)</td><td>securityLearning/29 ✅</td><td>互补,本系列讲可用性视角的事故响应</td></tr><tr><td>供应链安全</td><td>securityLearning/26 ✅</td><td>不重复,只在镜像签名一篇引用</td></tr><tr><td>AI Infra / LLM Ops</td><td>aiLearning ✅</td><td>不重复,只在 FinOps 提 GPU 成本</td></tr></tbody></table><p><strong>简单粗暴的判断</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;我代码本身有问题&quot;          → backendLearning / networkLearning</span></span>
<span class="line"><span>&quot;我系统挂了不知道为什么&quot;   → 本系列(可观测性 / 事故响应)</span></span>
<span class="line"><span>&quot;我系统总是挂&quot;             → 本系列(SLO / 容量 / 混沌)</span></span>
<span class="line"><span>&quot;我发布老出事&quot;             → 本系列(CI/CD / GitOps / 渐进发布)</span></span>
<span class="line"><span>&quot;我基础设施改不动&quot;         → 本系列(IaC)</span></span>
<span class="line"><span>&quot;我团队出事没人响应&quot;       → 本系列(On-call / 复盘)</span></span>
<span class="line"><span>&quot;我被攻击了&quot;               → securityLearning</span></span>
<span class="line"><span>&quot;我成本失控了&quot;             → 本系列 34 篇(FinOps)</span></span></code></pre></div><hr><h2 id="七、读完整套你应该有的本能" tabindex="-1">七、读完整套你应该有的本能 <a class="header-anchor" href="#七、读完整套你应该有的本能" aria-label="Permalink to &quot;七、读完整套你应该有的本能&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>看到任何一个新服务上线,你下意识地问:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  □ 它的 SLI 是什么(用户视角的&quot;可用&quot;长什么样)</span></span>
<span class="line"><span>  □ 错误预算给多少(SLO 99.5% 还是 99.9%)</span></span>
<span class="line"><span>  □ 黄金 4 信号的 dashboard 在哪</span></span>
<span class="line"><span>  □ 关键告警有 Runbook 吗</span></span>
<span class="line"><span>  □ 出事谁 On-call(轮值表在哪)</span></span>
<span class="line"><span>  □ 灰度怎么发(蓝绿 / 金丝雀 / FF)</span></span>
<span class="line"><span>  □ 自动回滚条件是什么</span></span>
<span class="line"><span>  □ 上次类似故障的 Postmortem 在哪</span></span>
<span class="line"><span>  □ 容量上限测过吗(单实例 / 整体)</span></span>
<span class="line"><span>  □ 跨可用区还是单可用区</span></span>
<span class="line"><span>  □ 依赖的下游 SLO 是多少</span></span>
<span class="line"><span>  □ 这次发布会燃烧多少错误预算</span></span>
<span class="line"><span></span></span>
<span class="line"><span>这套问题就是这个系列要教会你的&quot;反射&quot;</span></span></code></pre></div><p><strong>这套反射不是知识,是肌肉记忆</strong>——看到一个新服务,这 12 个问题在 30 秒内全部过一遍。问完一遍,要么这个服务是健壮的,要么你已经识别了 5 个风险。<strong>这就是&quot;对生产系统负责的人&quot;和&quot;只写代码的人&quot;的差别</strong>。</p><h3 id="_7-1-第二个硬指标-四份文档" tabindex="-1">7.1 第二个硬指标:四份文档 <a class="header-anchor" href="#_7-1-第二个硬指标-四份文档" aria-label="Permalink to &quot;7.1 第二个硬指标:四份文档&quot;">​</a></h3><p>看完整套之后,你应该能独立写出团队的:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 一份 SLO 文档</span></span>
<span class="line"><span>   - SLI 选择(用户视角)</span></span>
<span class="line"><span>   - 错误预算(月度 / 季度)</span></span>
<span class="line"><span>   - 政策(超支怎么办)</span></span>
<span class="line"><span>   - 燃烧率告警规则</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 一份事故响应手册</span></span>
<span class="line"><span>   - IC / Ops / Comms / Scribe 角色</span></span>
<span class="line"><span>   - 升级路径(5/15/30 分钟)</span></span>
<span class="line"><span>   - 战时频道模板</span></span>
<span class="line"><span>   - 时间线记录模板</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 一份发布门禁清单</span></span>
<span class="line"><span>   - CI 必过的检查项</span></span>
<span class="line"><span>   - 灰度策略(金丝雀比例 / 持续时间)</span></span>
<span class="line"><span>   - 自动 rollback 条件</span></span>
<span class="line"><span>   - 跨环境 promote 流程</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 一份 On-call 手册</span></span>
<span class="line"><span>   - 轮值表(Primary / Secondary)</span></span>
<span class="line"><span>   - 告警分级(P0/P1/P2)</span></span>
<span class="line"><span>   - 升级规则</span></span>
<span class="line"><span>   - 补偿政策(调休 / 加班费)</span></span></code></pre></div><p><strong>这四份文档不是模板填空——是你对自己团队的工程承诺</strong>。文档质量决定团队稳定性的上限。</p><hr><h2 id="八、立场声明" tabindex="-1">八、立场声明 <a class="header-anchor" href="#八、立场声明" aria-label="Permalink to &quot;八、立场声明&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这个系列的写作立场:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✓ 服务于&quot;对生产系统负责&quot;的工程师视角</span></span>
<span class="line"><span>   不是替开发背锅的运维,而是用软件工程方法把可靠性做成</span></span>
<span class="line"><span>   可度量、可管理、可改进的产品属性</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✓ 中型团队优先</span></span>
<span class="line"><span>   10 人 / 100 微服务 / 5000 QPS,大厂全球流量调度不讲</span></span>
<span class="line"><span>   Google / 字节级硬件运维不讲,小厂兼职 SRE 不讲</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✓ K8s + Prometheus + Loki + OTel + ArgoCD + Terraform 默认栈</span></span>
<span class="line"><span>   每篇标注&quot;换成 VM / 其他工具&quot;哪些结论还成立</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ 不讲&quot;DevOps 是文化&quot;这种口号</span></span>
<span class="line"><span>   文化要落到流程和工具上,不落地的文化是 PPT 文化</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ 不抄 Google SRE Book</span></span>
<span class="line"><span>   那两本书在那儿,这里只补它们对中型团队没讲透的工程细节</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ 不写&quot;装 Prometheus 三步走&quot;</span></span>
<span class="line"><span>   不是工具教程,是工程视角</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ 不堆 yaml</span></span>
<span class="line"><span>   只贴关键 20-50 行,讲清取舍理由</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ 不一刀切建议</span></span>
<span class="line"><span>   任何&quot;必须 / 一定 / 永远不要&quot;都给适用条件</span></span></code></pre></div><hr><h2 id="九、踩坑提醒-总览版-后面每篇细讲" tabindex="-1">九、踩坑提醒(总览版,后面每篇细讲) <a class="header-anchor" href="#九、踩坑提醒-总览版-后面每篇细讲" aria-label="Permalink to &quot;九、踩坑提醒(总览版,后面每篇细讲)&quot;">​</a></h2><ol><li><strong>把 SRE 当高级运维</strong>——这是国内最大的误解,SRE 是工程师,不是修工</li><li><strong>照搬 Google SRE Book</strong>——前提条件不一样,50% 时间 / 停发版 / 大规模自动化都会翻车</li><li><strong>以为&quot;上了 K8s 就 DevOps&quot;</strong>——K8s 只是底座,可观测性 / SLO / 发布 / On-call 一样都不能少</li><li><strong>不定 SLO 喊 99.99%</strong>——商务承诺空头支票,出事就是违约</li><li><strong>告警按静态阈值配</strong>——必然爆炸,真信号被噪声淹</li><li><strong>没有 On-call 制度</strong>——靠&quot;老张随时在线&quot;,老张离职日就是断手日</li><li><strong>盲目自动化</strong>——自动化没价值的 Toil,反而造新的 Toil</li><li><strong>复盘变扯皮</strong>——blameless 不是空话,是工程纪律</li><li><strong>不做容量规划</strong>——以为云能弹无限,某天遇到限额秒挂</li><li><strong>IaC 当文档用</strong>——Terraform 仓库挂在那儿,实际所有变更走控制台</li><li><strong>CI/CD 只追快</strong>——发布 10 分钟一次但失败率 30%,稳定性反而下降</li><li><strong>复盘没 follow-up</strong>——同样的事故 6 周后重演</li></ol><p><strong>这 12 条每条对应这个系列的一篇文章</strong>——下面 33 篇就是这 12 条坑的逐个填补。</p><hr><h2 id="十、节奏建议" tabindex="-1">十、节奏建议 <a class="header-anchor" href="#十、节奏建议" aria-label="Permalink to &quot;十、节奏建议&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>建议阅读节奏:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 1 周:第一层 4 篇(本篇 + 02 + 03 + 04)</span></span>
<span class="line"><span>        全是&quot;心智文章&quot;,看完心里有底了再往下走</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 2-3 周:第二层 8 篇(05-12)</span></span>
<span class="line"><span>        可观测性最值钱,建议跟着自己团队的 Prometheus 实操</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 4 周:第三层 5 篇(13-17)</span></span>
<span class="line"><span>        SLO 工程,**这一周读完后立刻给自己服务定一份 SLO**</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 5-6 周:第四层 6 篇(18-23)</span></span>
<span class="line"><span>        CI/CD,跟着自己团队的发布流程对照</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 7 周:第五层 4 篇(24-27)</span></span>
<span class="line"><span>        IaC,**这一周用 Terraform 写一个 minimal 项目**</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 8 周以后:第六层 7 篇(28-34)</span></span>
<span class="line"><span>        生产实战,每篇都对应&quot;你这周可能要做的事&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>总耗时:8-12 周,大致两到三个月</span></span></code></pre></div><p><strong>不要一口气读完</strong>——这套东西消化需要时间,每读完一篇试着应用到自己团队 1-2 个动作,<strong>比连续读 34 篇但什么都不改&quot;读得快&quot;得多</strong>。</p><hr><h2 id="十一、小结-你为什么读这个系列" tabindex="-1">十一、小结:你为什么读这个系列 <a class="header-anchor" href="#十一、小结-你为什么读这个系列" aria-label="Permalink to &quot;十一、小结:你为什么读这个系列&quot;">​</a></h2><p>回到开篇:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;你不再只是把代码合到 main 上的工程师&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>读完这个系列之后,你会:</span></span>
<span class="line"><span>   - 知道&quot;代码上线&quot;只是工作的 30%,剩下 70% 是看不见的工程</span></span>
<span class="line"><span>   - 知道 SLO / 告警 / On-call / 复盘 不是运维的事,是工程师的事</span></span>
<span class="line"><span>   - 知道任何&quot;100% 可用&quot;承诺都是空头支票</span></span>
<span class="line"><span>   - 知道失败是常态,系统设计要为失败准备</span></span>
<span class="line"><span>   - 知道&quot;自动化&quot;不是答案,是工具</span></span>
<span class="line"><span>   - 知道复盘不是甩锅会,是工程改进会</span></span>
<span class="line"><span></span></span>
<span class="line"><span>最终,你成为团队里&quot;对生产系统负责&quot;的那个人</span></span>
<span class="line"><span>   不是头衔,是能力——</span></span>
<span class="line"><span>   出事时大家自然会看向你,因为你能拍板、能定位、能修复</span></span></code></pre></div><p><strong>SRE 这门手艺,在国内被严重低估</strong>——很多公司还在用招&quot;高级运维&quot;的薪资招&quot;SRE 工程师&quot;。<strong>但这种错配不会一直持续</strong>——任何业务到了规模就一定会撞上可靠性问题,撞上了才会发现这个能力的稀缺。<strong>你提前练这套手艺,就是给自己积复利</strong>。</p><hr><p>下一篇:<strong><code>02-Google-SRE精华.md</code></strong>——这一篇讲 SRE 的&quot;概念图&quot;,下一篇讲 Google 给的&quot;具体范式&quot;。<strong>不会翻译整本 SRE Book</strong>(那本书自己读才有用),只挑 4 个对中型团队<strong>最有用的概念</strong>:</p><ul><li><strong>错误预算</strong>(99.9% = 一个月 43 分钟,这 43 分钟该花在哪)</li><li><strong>Toil</strong>(机械可重复无长期价值,怎么识别怎么消灭)</li><li><strong>50% 工程时间</strong>(Google 怎么落地,中型团队怎么改造)</li><li><strong>黄金信号</strong>(Latency / Traffic / Errors / Saturation,为什么是 4 个不是 7 个)</li></ul><p>结尾给一段&quot;<strong>哪些直接抄,哪些必须改,哪些千万别学</strong>&quot;——把 Google 范式翻译成中型团队能用的版本。读完这两篇,你对 SRE 这门手艺的整体框架就建立了。</p>`,118)])])}const h=n(e,[["render",t]]);export{g as __pageData,h as default};
